    embedding_client: Arc<dyn EmbeddingClient>, // Generates embeddings
    vector_store: Arc<dyn VectorStore>,        // Stores/searches vectors
}

impl RagAgent {
    pub async fn complete_with_rag(&self, query: &str) -> Result<CompletionResponse> {
        // 1. Embed query
        let query_embedding = self.embedding_client.embed_text(query).await?;

        // 2. Search vector store
        let context_docs = self.vector_store.search(query_embedding.vector, top_k).await?;

        // 3. Build request with context
        let request = build_request_with_context(query, context_docs);

        // 4. Delegate to agent for completion
        self.agent.complete(request).await
    }
}
```

